{
  "name": "react-project",
  "version": "1.0.0",
  "description": "A React project",
  "dependencies": {
    "react": "^16.13.1",
    "react-dom": "^16.13.1"
  },
  "scripts": {
    "start": "react-scripts start",
    "build": "react-scripts build",
    "test": "react-scripts test",
    "eject": "react-scripts eject"
  },
  "keywords": [
    "react",
    "project"
  ],
  "author": "Your Name",
  "license": "MIT"
}

body {
  font-family: Arial, sans-serif;
  background-color: #f2f2f2;
  margin: 0;
  padding: 0;
}

#root {
  display: flex;
  justify-content: center;
  align-items: center;
  height: 100vh;
}

h1 {
  color: #333;
  text-align: center;
}

import React from 'react';
import ReactDOM from 'react-dom';
import App from './components/App';

ReactDOM.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>,
  document.getElementById('root')
);

import React from 'react';
import Header from './Header';
import Footer from './Footer';

const App = () => {
  return (
    <div>
      <Header />
      <h1>Welcome to my React App!</h1>
      <p>This is the main content of the app.</p>
      <Footer />
    </div>
  );
};

export default App;

import React from 'react';

const Header = () => {
  return (
    <header>
      <h1>My React App</h1>
      <nav>
        <ul>
          <li>Home</li>
          <li>About</li>
          <li>Contact</li>
        </ul>
      </nav>
    </header>
  );
};

export default Header;

import React from 'react';

const Footer = () => {
  return (
    <footer>
      <p>&copy; 2021 My React App. All rights reserved.</p>
    </footer>
  );
};

export default Footer;

body {
  margin: 0;
  padding: 0;
  font-family: Arial, sans-serif;
}

h1 {
  color: #333;
  text-align: center;
}

p {
  color: #666;
  text-align: center;
}

ul {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  justify-content: center;
}

li {
  margin: 0 10px;
}

footer {
  background-color: #f2f2f2;
  padding: 10px;
  text-align: center;
}
